            handlePushNotifications(message: message)
        case "inAppPurchase":
            handleInAppPurchase(message: message)
        case "nativeAction":
            handleNativeAction(message: message)
        default:
            break
        }
    }
    
    private func handleCameraAccess(message: WKScriptMessage) {
        guard let body = message.body as? [String: Any],
              let action = body["action"] as? String else { return }
        
        switch action {
        case "openCamera":
            openCamera()
        case "openPhotoLibrary":
            openPhotoLibrary()
        default:
            break
        }
    }
    
    private func openCamera() {
        DispatchQueue.main.async {
            guard UIImagePickerController.isSourceTypeAvailable(.camera) else {
                self.sendMessageToWeb(event: "cameraError", data: ["error": "Camera not available"])
                return
            }
            
            let picker = UIImagePickerController()
            picker.sourceType = .camera
            picker.delegate = self
            picker.allowsEditing = true
            self.present(picker, animated: true)
        }
    }
    
    private func openPhotoLibrary() {
        DispatchQueue.main.async {
            let picker = UIImagePickerController()
            picker.sourceType = .photoLibrary
            picker.delegate = self
            picker.allowsEditing = true
            self.present(picker, animated: true)
        }
    }
    
    private func handlePushNotifications(message: WKScriptMessage) {
        guard let body = message.body as? [String: Any],
              let action = body["action"] as? String else { return }
        
        switch action {
        case "requestPermission":
            requestPushNotificationPermission()
        case "getToken":
            getDeviceToken()
        default:
            break
        }
    }
    
    private func requestPushNotificationPermission() {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { granted, error in
            DispatchQueue.main.async {
                if granted {
                    UIApplication.shared.registerForRemoteNotifications()
                    self.sendMessageToWeb(event: "pushPermissionGranted", data: ["granted": true])
                } else {
                    self.sendMessageToWeb(event: "pushPermissionDenied", data: ["granted": false, "error": error?.localizedDescription ?? "Permission denied"])
                }
            }
        }
    }
    
    private func getDeviceToken() {
        if let token = UserDefaults.standard.string(forKey: "deviceToken") {
            sendMessageToWeb(event: "deviceToken", data: ["token": token])
        } else {
            sendMessageToWeb(event: "deviceTokenError", data: ["error": "Token not available"])
        }
    }
    
    private func handleInAppPurchase(message: WKScriptMessage) {
        guard let body = message.body as? [String: Any],
              let action = body["action"] as? String else { return }
        
        switch action {
        case "purchase":
            if let productId = body["productId"] as? String {
                purchaseProduct(productId: productId)
            }
        case "restore":
            restorePurchases()
        case "getProducts":
            if let productIds = body["productIds"] as? [String] {
                fetchProducts(productIds: productIds)
            }
        default:
            break
        }
    }
    
    private func purchaseProduct(productId: String) {
        InAppPurchaseManager.shared.purchaseProduct(productId: productId) { success, error in
            if success {
                self.sendMessageToWeb(event: "purchaseSuccess", data: ["productId": productId])
            } else {
                self.sendMessageToWeb(event: "purchaseError", data: ["productId": productId, "error": error ?? "Unknown error"])
            }
        }
    }
    
    private func restorePurchases() {
        InAppPurchaseManager.shared.restorePurchases { success, error in
            if success {
                self.sendMessageToWeb(event: "restoreSuccess", data: [:])
            } else {
                self.sendMessageToWeb(event: "restoreError", data: ["error": error ?? "Unknown error"])
            }
        }
    }
    
    private func fetchProducts(productIds: [String]) {
        InAppPurchaseManager.shared.fetchProducts(productIds: productIds) { products in
            let productsData = products.map { product in
                return [
                    "productId": product.productIdentifier,
                    "title": product.localizedTitle,
                    "description": product.localizedDescription,
                    "price": product.price.stringValue,
                    "priceLocale": product.priceLocale.currencyCode ?? ""
                ]
            }
            self.sendMessageToWeb(event: "productsLoaded", data: ["products": productsData])
        }
    }
    
    private func handleNativeAction(message: WKScriptMessage) {
        guard let body = message.body as? [String: Any],
              let action = body["action"] as? String else { return }
        
        switch action {
        case "share":
            if let text = body["text"] as? String {
                shareContent(text: text, url: body["url"] as? String)
            }
        case "vibrate":
            vibrateDevice()
        case "openURL":
            if let urlString = body["url"] as? String {
                openExternalURL(urlString: urlString)
            }
        case "getBatteryLevel":
            getBatteryLevel()
        case "getDeviceInfo":
            getDeviceInfo()
        default:
            break
        }
    }
    
    private func shareContent(text: String, url: String?) {
        var items: [Any] = [text]
        if let urlString = url, let shareURL = URL(string: urlString) {
            items.append(shareURL)
        }
        
        DispatchQueue.main.async {
            let activityVC = UIActivityViewController(activityItems: items, applicationActivities: nil)
            if let popoverController = activityVC.popoverPresentationController {
                popoverController.sourceView = self.view
                popoverController.sourceRect = CGRect(x: self.view.bounds.midX, y: self.view.bounds.midY, width: 0, height: 0)
                popoverController.permittedArrowDirections = []
            }
            self.present(activityVC, animated: true)
        }
    }
    
    private func vibrateDevice() {
        let generator = UINotificationFeedbackGenerator()
        generator.notificationOccurred(.success)
    }
    
    private func openExternalURL(urlString: String) {
        guard let url = URL(string: urlString) else { return }
        if UIApplication.shared.canOpenURL(url) {
            UIApplication.shared.open(url)
        }
    }
    
    private func getBatteryLevel() {
        UIDevice.current.isBatteryMonitoringEnabled = true
        let batteryLevel = UIDevice.current.batteryLevel
        sendMessageToWeb(event: "batteryLevel", data: ["level": batteryLevel >= 0 ? batteryLevel : -1])
    }
    
    private func getDeviceInfo() {
        let device = UIDevice.current
        let deviceInfo: [String: Any] = [
            "model": device.model,
            "systemName": device.systemName,
            "systemVersion": device.systemVersion,
            "name": device.name,
            "identifierForVendor": device.identifierForVendor?.uuidString ?? ""
        ]
        sendMessageToWeb(event: "deviceInfo", data: deviceInfo)
    }
    
    private func sendMessageToWeb(event: String, data: [String: Any]) {
        do {
            let jsonData = try JSONSerialization.data(withJSONObject: data)
            let jsonString = String(data: jsonData, encoding: .utf8) ?? "{}"
            let script = "window.dispatchEvent(new CustomEvent('\(event)', { detail: \(jsonString) }));"
            webView.evaluateJavaScript(script)
        } catch {
            print("Error serializing data: \(error)")
        }
    }
}

extension HybridWebViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        progressView.isHidden = true
    }
    
    func webView(_ webView: WKWebView, didStartProvisionalNavigation navigation: WKNavigation!) {
        progressView.isHidden = false
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        progressView.isHidden = true
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        if let url = navigationAction.request.url {
            if url.scheme == "tel" || url.scheme == "mailto" {
                UIApplication.shared.open(url)
                decisionHandler(.cancel)
                return
            }
        }
        decisionHandler(.allow)
    }
}

extension HybridWebViewController: WKUIDelegate {
